-- =====================================================================
-- 0043: 13 months of card ****8300, transcribed from the owner's SMS
-- recording (8 Jul 2025 -> 17 Jul 2026). Column meanings live in 0042.
--
-- Idempotent: the unique index on (source, balance_after, amount) turns a
-- re-run into a no-op, and any row the owner has re-categorised is protected
-- by category_edited, so his corrections survive.
--
-- The category set here is a FIRST GUESS from the merchant text:
--   · anything at an ATM of 2,000+  -> cash_stock (cash drawn to buy stock)
--   · anything at an ATM under that -> cash_small (could be either)
--   · named shops                   -> eating_out / groceries / fuel_car / bills
--   · a readable shop we cannot classify -> personal_other, NOT a guessed industry
-- One row has balance_derived = true: its message was clipped off screen, so
-- the balance was computed from the rows either side. It is forced arithmetic,
-- not an estimate -- 13,406.61 - 1,008.90 - 125.00 = 12,272.71, exactly what
-- the next message reports.
-- =====================================================================

insert into bank_transactions
  (txn_date,merchant,place,bank,direction,amount,balance_after,category,side,
   chain_gap,deposit_amount,is_reversal_refund,balance_derived,seen_count,raw)
